/* ─── Onboarding Wizard ──────────────────────────────────── */

/* Overlay */
.onboarding-wizard-overlay {
    position: fixed;
    inset: 0;
    display: flex;
    justify-content: center;
    align-items: center;
    background-color: var(--bg-backdrop-heavy);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    z-index: 140;
}

/* Card */
.onboarding-wizard-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 100%;
    max-width: 500px;
    max-height: 90vh;
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    box-shadow: var(--shadow-modal);
    border-radius: 16px;
    padding: 28px 28px 32px;
    overflow-y: auto;
    overflow-x: hidden;
}

/* Content wrapper */
.onboarding-wizard-content {
    width: 100%;
    position: relative;
    overflow: hidden;
}

.onboarding-step-wrapper {
    width: 100%;
}

/* ─── Progress Bar ───────────────────────────────────────── */

.onboarding-progress-bar {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;

