215→export const uploadJournalContentService = async(
216→    content,
217→    title,
218→    userId,
219→    remixSourceJournalId = null,
220→    isRemix = false,
221→    promptId = null
222→) =>{
223→    if(!userId){
224→        console.error('userId is undefined');
225→        throw {status: 400, error: 'userId is undefined'};
226→    }
227→
228→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
229→
230→    if(!trimmedTitle){
231→        console.error('title is missing!');
232→        throw {status: 400, error: 'title is missing!'};
233→    }
234→
235→    const shouldSaveRemixMetadata = Boolean(
236→        remixSourceJournalId
237→        && typeof remixSourceJournalId === 'string'
238→        && remixSourceJournalId.trim()
239→    );
240→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
241→
242→    if(!content){
243→        console.error('content is missing for text post!');
244→        throw {status: 400, error: 'content is missing for text post'};
245→    }
246→
247→    const parseData = parseTextContentSafely(content);
248→    if(!parseData){
249→        console.error('error while parsing text content data');
250→        throw {status: 400, error: 'error while parsing text content data'};
251→    }
252→
253→    const embeddingBody = parseData.wholeText || '';
254→    const payload = {
255→        user_id: userId,
256→        title: trimmedTitle,
257→        post_type: POST_TYPE_TEXT,
258→        content: content,
259→    };
260→
261→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
262→
263→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
264→        console.error('error while generating embeddings on a post!');
265→        throw {status: 400, error: 'error while generating embeddings on a post!'};
266→    }
267→
268→    const insertPayload = {
269→        ...payload,
270→        embeddings: embeddingResult
271→    };
272→
273→    if(normalizedIsRemix){
274→        insertPayload.is_remix = true;
275→    }
276→    if(shouldSaveRemixMetadata){
277→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
278→    }
279→    if(promptId){
280→        const parsedPromptId = parseInt(promptId, 10);
281→        if(!isNaN(parsedPromptId)){
282→            insertPayload.prompt_id = parsedPromptId;
283→        }
284→    }
285→
286→    let {error} = await supabase
287→    .from('journals')
288→    .insert(insertPayload);
289→
290→    if(error){
291→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
292→        if(missingRemixColumns){
293→            const fallbackPayload = {
294→                ...payload,
295→                embeddings: embeddingResult
296→            };
297→
298→            const retry = await supabase
299→            .from('journals')
300→            .insert(fallbackPayload);
301→            error = retry.error;
302→        }
303→    }
304→
305→    if(error){
306→        console.error('supabase error while uploading content:',error.message);
307→        throw {status: 500, error: 'supabase error while uploading content'};
308→    }
309→
310→    // Non-fatal: record publish for writing streak
311→    let streakResult = null;
312→    try {
313→        const { recordPublishForStreak } = await import('./streakService.js');
314→        streakResult = await recordPublishForStreak(userId);
315→    } catch (streakErr) {
316→        console.error('non-fatal: streak record failed:', streakErr?.message || streakErr);
317→    }
318→
319→    return { success: true, streakResult };
320→}
