  30→const extractBearerToken = (authHeader = "") => {
  31→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
  32→    if (!trimmed) return "";
  33→
  34→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
  35→    if (bearerMatch?.[1]) {
  36→        return bearerMatch[1].trim();
  37→    }
  38→
  39→    return trimmed;
