 342→router.get('/getNotifications', requireAuth, async(req, res) =>{
 343→    const {before} = req.query;
 344→    const userId = req.userId;
 345→    const parsedLimit = parseLimitWithinRange(
 346→        req.query.limit,
 347→        NOTIFICATION_LIMIT_MIN,
 348→        NOTIFICATION_LIMIT_MAX,
 349→        NOTIFICATION_DEFAULT_LIMIT
 350→    );
 351→
 352→    if(parsedLimit == null){
 353→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
 354→    }
 355→
 356→    // Fetch a generous amount from both tables, then merge and paginate
 357→    const fetchLimit = parsedLimit + 1;
 358→
 359→    let journalQuery = supabase
 360→    .from('notifications')
 361→    .select(NOTIFICATION_JOURNAL_SELECT)
 362→    .eq('receiver_id', userId)
 363→    .order('created_at', {ascending: false})
 364→    .order('id', {ascending: false})
 365→    .limit(fetchLimit)
 366→
 367→    let opinionQuery = supabase
 368→    .from('notification_opinions')
 369→    .select(NOTIFICATION_OPINION_SELECT)
 370→    .eq('receiver_id', userId)
 371→    .order('created_at', {ascending: false})
 372→    .order('id', {ascending: false})
 373→    .limit(fetchLimit)
 374→
 375→    if(before){
 376→        journalQuery = journalQuery.lt('created_at', before);
 377→        opinionQuery = opinionQuery.lt('created_at', before);
 378→    }
 379→
 380→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 381→
 382→    if(journalResult.error){
 383→        console.error('error while fetching data from notification table:', journalResult.error);
 384→        return res.status(500).json({error: 'error fetching data from notification table'});
 385→    }
 386→    if(opinionResult.error){
 387→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 388→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 389→    }
 390→
 391→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 392→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 393→
 394→    // Merge and sort by created_at descending
 395→    const merged = [...journalNotifs, ...opinionNotifs]
 396→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 397→
 398→    // Likes/bookmarks lookup only for journal notifications
 399→    const journalIds = [...new Set(
 400→        merged
 401→            .filter((n) => n.source === 'journal')
 402→            .map((n) => n.journal_id)
 403→            .filter(Boolean)
 404→    )];
 405→
 406→    let hasLikedResult = [];
 407→    let hasBookMarkedResult = [];
 408→    if(journalIds.length > 0){
 409→        const [hasLiked, hasBookMarked] = await Promise.all([
 410→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 411→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 412→        ]);
 413→
 414→        if(hasLiked.error || hasBookMarked.error){
 415→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 416→        }
 417→        hasLikedResult = hasLiked.data || [];
 418→        hasBookMarkedResult = hasBookMarked.data || [];
 419→    }
 420→
 421→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 422→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 423→
 424→    const formatted = merged.map((notif) => ({
 425→        ...notif,
 426→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 427→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 428→    }))
 429→
 430→    const hasMore = formatted.length > parsedLimit;
 431→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
 432→
 433→    return res.status(200).json(
 434→        {
 435→            hasMore: hasMore,
 436→            data: slicedData,
 437→        }
 438→    )
 439→
 440→})
