431→export const getJournalsService = async(limit, userId, before) => {
432→    if(isNaN(limit) || limit > 20 || limit < 1){
433→        console.error('limit should be intiger, not below 1 and higher than 20');
434→        throw {status: 400, error: 'limit should be intiger, not below 1 and higher than 20'};
435→    }
436→
437→    const parsedLimit = parseInt(limit);
438→
439→    let query = supabase
440→    .from('journals')
441→    .select(JOURNAL_WITH_COUNTS_SELECT)
442→    .eq('privacy', 'public')
443→    .order('created_at', {ascending: false})
444→    .order('id', {ascending: false})
445→    .limit(parsedLimit + 1);
446→
447→    if(before){
448→        query = query.lt('created_at', before);
449→    }
450→
451→    const {data, error} = await query;
452→
453→    if(error){
454→        console.error('supabase error while fetching journals:', error.message);
455→        throw{status: 500, error: 'supabase error while fetching journals'}
456→    }
457→
458→    if(data.length === 0){
459→        const journalData = {
460→            data: [],
461→            hasMore: false
462→        }
463→        return journalData
464→    }
465→
466→    // If userId is provided, fetch personalization (likes/bookmarks/reactions)
467→    // Otherwise return journals with has_liked/has_bookmarked/user_reaction defaulting to false/null
468→    let userHasLikedSet = new Set();
469→    let userHasBookmarkedSet = new Set();
470→    let userReactionMap = new Map();
471→
472→    if(userId){
473→        const journalIds = data.map((journal) => journal.id);
474→
475→        const [userLikes, userBookmarks, userReactions] = await Promise.all([
476→            supabase
477→            .from('likes')
478→            .select('journal_id')
479→            .in('journal_id', journalIds)
480→            .eq('user_id', userId),
481→
482→            supabase
483→            .from('bookmarks')
484→            .select('journal_id')
485→            .in('journal_id', journalIds)
486→            .eq('user_id', userId),
487→
488→            supabase
489→            .from('reactions')
490→            .select('journal_id, reaction_type')
491→            .in('journal_id', journalIds)
492→            .eq('user_id', userId)
493→        ]);
494→
495→        const {data: userLikesResult, error: errorUserLikeResult} = userLikes;
496→        const {data: userBookmarksResult, error: errorUserBookmarksResult} = userBookmarks;
497→        const {data: userReactionsResult} = userReactions;
498→
499→        if(errorUserLikeResult || errorUserBookmarksResult) {
500→            console.error('supabase error:', errorUserLikeResult?.message || errorUserBookmarksResult?.message);
501→            throw {status: 500, error: 'supabase error on fetching user likes or user bookmarks'}
502→        }
503→
504→        userHasLikedSet = new Set(userLikesResult?.map((j) => j.journal_id) || []);
505→        userHasBookmarkedSet = new Set(userBookmarksResult?.map((j) => j.journal_id)|| []);
506→        userReactionMap = new Map((userReactionsResult || []).map((r) => [r.journal_id, r.reaction_type]));
507→    }
508→
509→    await attachRepostSources(data);
510→
511→    const formattedData = data?.map((journal) => ({
512→        ...journal,
513→        has_liked: userHasLikedSet.has(journal.id),
514→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
515→        user_reaction: userReactionMap.get(journal.id) || null
516→    }))
517→
518→    const hasMore = data?.length > parsedLimit;
519→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
520→
521→    const journalData = {
522→        data: slicedData,
523→        hasMore: hasMore
524→    }
525→    return journalData;
526→}
