 1→import supabase from "./supabase.js";
 2→
 3→const CONFIDENCE_TIERS = {
 4→    high:   { threshold: 0.60, maxResults: 5, label: 'high' },
 5→    medium: { threshold: 0.48, maxResults: 3, label: 'medium' },
 6→    low:    { threshold: 0.38, maxResults: 2, label: 'low' },
 7→};
 8→
 9→async function getDynamicFloor() {
10→    const { count, error } = await supabase
11→        .from('journals')
12→        .select('id', { count: 'exact', head: true })
13→        .eq('privacy', 'public')
14→        .not('embeddings', 'is', null);
15→
16→    if (error) {
17→        console.error('getDynamicFloor count error:', error.message);
18→        return 0.30;
19→    }
20→
21→    if (count < 500)  return 0.35;
22→    if (count < 2000) return 0.40;
23→    return 0.45;
24→}
25→
26→function getConfidenceTier(topSimilarity) {
27→    if (topSimilarity >= CONFIDENCE_TIERS.high.threshold)   return CONFIDENCE_TIERS.high;
28→    if (topSimilarity >= CONFIDENCE_TIERS.medium.threshold) return CONFIDENCE_TIERS.medium;
29→    if (topSimilarity >= CONFIDENCE_TIERS.low.threshold)    return CONFIDENCE_TIERS.low;
30→    return null;
31→}
32→
33→export async function getRelatedPostsService(journalId) {
34→    const dynamicFloor = await getDynamicFloor();
35→
36→    // First attempt with dynamic floor
37→    let { data, error } = await supabase.rpc('find_related_posts', {
38→        source_post_id: journalId,
39→        match_count: 8,
40→        similarity_floor: dynamicFloor,
41→        recency_days: 365,
42→    });
43→
44→    if (error) {
45→        throw { status: 500, error: 'Failed to find related posts: ' + error.message };
46→    }
47→
48→    // Fallback: if < 2 results, try with a lower floor
49→    if (!data || data.length < 2) {
50→        const lowerFloor = Math.max(dynamicFloor - 0.03, 0.30);
51→        if (lowerFloor < dynamicFloor) {
52→            const fallback = await supabase.rpc('find_related_posts', {
53→                source_post_id: journalId,
54→                match_count: 8,
55→                similarity_floor: lowerFloor,
56→                recency_days: 365,
57→            });
58→            if (!fallback.error && fallback.data && fallback.data.length >= 2) {
59→                data = fallback.data;
60→            }
61→        }
62→    }
63→
64→    // Never show fewer than 2 results
65→    if (!data || data.length < 2) {
66→        return { posts: [], confidence: 'none', topSimilarity: 0 };
67→    }
68→
69→    const topSimilarity = data[0]?.semantic_similarity || 0;
70→    const tier = getConfidenceTier(topSimilarity);
71→
72→    if (!tier) {
73→        return { posts: [], confidence: 'none', topSimilarity };
74→    }
75→
76→    // Cap results by confidence tier
77→    const cappedPosts = data.slice(0, tier.maxResults);
78→
79→    // Ensure we still have at least 2 after capping
80→    if (cappedPosts.length < 2) {
81→        return { posts: [], confidence: 'none', topSimilarity };
82→    }
83→
84→    return {
85→        posts: cappedPosts,
86→        confidence: tier.label,
87→        topSimilarity,
88→    };
89→}
