 3→/**
 4→ * Get today's writing prompt.
 5→ * Uses dayOfYear % promptCount for deterministic rotation.
 6→ */
 7→export const getTodaysPromptService = async () => {
 8→    // Get total prompt count
 9→    const { count, error: countErr } = await supabase
10→        .from('writing_prompts')
11→        .select('id', { count: 'exact', head: true });
12→
13→    if (countErr || !count || count === 0) {
14→        console.error('error getting prompt count:', countErr?.message);
15→        return null;
16→    }
17→
18→    // Calculate today's prompt index
19→    const now = new Date();
20→    const startOfYear = new Date(now.getFullYear(), 0, 0);
21→    const diff = now - startOfYear;
22→    const dayOfYear = Math.floor(diff / (1000 * 60 * 60 * 24));
23→    const promptIndex = dayOfYear % count;
24→
25→    // Fetch the prompt at that index (ordered by id ASC)
26→    const { data, error } = await supabase
27→        .from('writing_prompts')
28→        .select('*')
29→        .order('id', { ascending: true })
30→        .range(promptIndex, promptIndex)
31→        .single();
32→
33→    if (error) {
34→        console.error('error fetching today\'s prompt:', error.message);
35→        return null;
36→    }
37→
38→    return data;
39→};
