 342→router.get('/getNotifications', requireAuth, async(req, res) =>{
 343→    const {before} = req.query;
 344→    const userId = req.userId;
 345→    const parsedLimit = parseLimitWithinRange(
 346→        req.query.limit,
 347→        NOTIFICATION_LIMIT_MIN,
 348→        NOTIFICATION_LIMIT_MAX,
 349→        NOTIFICATION_DEFAULT_LIMIT
 350→    );
 351→
 352→    if(parsedLimit == null){
 353→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
 354→    }
 355→
 356→    // Fetch a generous amount from both tables, then merge and paginate
 357→    const fetchLimit = parsedLimit + 1;
 358→
 359→    let journalQuery = supabase
 360→    .from('notifications')
 361→    .select(NOTIFICATION_JOURNAL_SELECT)
 362→    .eq('receiver_id', userId)
 363→    .order('created_at', {ascending: false})
 364→    .order('id', {ascending: false})
 365→    .limit(fetchLimit)
 366→
 367→    let opinionQuery = supabase
 368→    .from('notification_opinions')
 369→    .select(NOTIFICATION_OPINION_SELECT)
 370→    .eq('receiver_id', userId)
 371→    .order('created_at', {ascending: false})
 372→    .order('id', {ascending: false})
 373→    .limit(fetchLimit)
 374→
 375→    if(before){
 376→        journalQuery = journalQuery.lt('created_at', before);
 377→        opinionQuery = opinionQuery.lt('created_at', before);
 378→    }
 379→
 380→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 381→
