```

### 0E. Backfill Script for Existing Users

**New file: `C:/Users/johnm/iskrib_v3/server/scripts/backfillInterestEmbeddings.js`**

```javascript
import supabase from '../services/supabase.js';
import { generateInterestsEmbedding } from '../services/interestEmbeddingService.js';

async function backfill() {
    // Fetch users who have writing_interests but no interests_embedding
    const { data: users, error } = await supabase
        .from('users')
        .select('id, writing_interests')
        .is('interests_embedding', null)
        .not('writing_interests', 'eq', '{}');

    if (error) {
        console.error('failed to fetch users:', error.message);
        process.exit(1);
    }

    console.log(`Found ${users.length} users to backfill`);

    let success = 0;
    for (const user of users) {
        if (!user.writing_interests || user.writing_interests.length === 0) continue;

        const embedding = await generateInterestsEmbedding(user.writing_interests);
        if (!embedding) continue;

        const { error: updateError } = await supabase
            .from('users')
            .update({ interests_embedding: embedding })
            .eq('id', user.id);

        if (updateError) {
            console.error(`failed to update user ${user.id}:`, updateError.message);
        } else {
            success++;
        }
    }

    console.log(`Backfill complete: ${success}/${users.length} users updated`);
    process.exit(0);
}

backfill();
